import { describe, it, expect, beforeEach } from 'vitest';
import { Database, resetDatabase } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { AnalyticsQuery } from '../../src/models/analytics.js';
import type { Order, OrderStatus } from '../../src/models/order.js';

/**
 * Helper to create and save an order directly into the repository.
 */
function makeOrder(
  repo: OrderRepository,
  overrides: Partial<Order> & { id: string; userId: string },
): Order {
  const order: Order = {
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 10,
    status: 'pending',
    createdAt: new Date('2024-01-15'),
    updatedAt: new Date('2024-01-15'),
    ...overrides,
  };
  repo.save(order);
  return order;
}

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    resetDatabase();
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  // ─── computeMetricValue (tested via getMetricSummary) ───

  describe('total-orders metric', () => {
    it('should count orders in the date range', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', createdAt: new Date('2024-01-10') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', createdAt: new Date('2024-01-20') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('total-orders', query);
      expect(summary.currentValue).toBe(2);
    });

    it('should exclude orders outside the date range', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', createdAt: new Date('2023-12-31') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', createdAt: new Date('2024-02-01') });
      makeOrder(orderRepo, { id: 'o3', userId: 'u1', createdAt: new Date('2024-01-15') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('total-orders', query);
      expect(summary.currentValue).toBe(1);
    });
  });

  describe('total-revenue metric', () => {
    it('should sum order totals', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', total: 50, createdAt: new Date('2024-01-10') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', total: 75.5, createdAt: new Date('2024-01-20') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('total-revenue', query);
      expect(summary.currentValue).toBe(125.5);
    });
  });

  describe('active-users metric', () => {
    it('should count distinct userIds', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', createdAt: new Date('2024-01-10') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', createdAt: new Date('2024-01-11') });
      makeOrder(orderRepo, { id: 'o3', userId: 'u2', createdAt: new Date('2024-01-12') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('active-users', query);
      expect(summary.currentValue).toBe(2);
    });
  });

  describe('order-completion-rate metric', () => {
    it('should compute percentage of delivered orders', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', status: 'delivered', createdAt: new Date('2024-01-10') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', status: 'delivered', createdAt: new Date('2024-01-11') });
      makeOrder(orderRepo, { id: 'o3', userId: 'u1', status: 'pending', createdAt: new Date('2024-01-12') });
      makeOrder(orderRepo, { id: 'o4', userId: 'u1', status: 'cancelled', createdAt: new Date('2024-01-13') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('order-completion-rate', query);
      expect(summary.currentValue).toBe(50); // 2/4 = 50%
    });

    it('should return 0 when no orders exist', () => {
      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('order-completion-rate', query);
      expect(summary.currentValue).toBe(0);
    });
  });

  // ─── getMetricSummary — trend & comparison ───

  describe('getMetricSummary', () => {
    it('should compute previous period and trend=up when current > previous', () => {
      // Previous period: Dec 1-31, Current period: Jan 1-31
      makeOrder(orderRepo, { id: 'o-prev', userId: 'u1', createdAt: new Date('2023-12-15') });
      makeOrder(orderRepo, { id: 'o-cur1', userId: 'u1', createdAt: new Date('2024-01-10') });
      makeOrder(orderRepo, { id: 'o-cur2', userId: 'u1', createdAt: new Date('2024-01-20') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('total-orders', query);
      expect(summary.currentValue).toBe(2);
      expect(summary.previousValue).toBe(1);
      expect(summary.changePercent).toBe(100); // (2-1)/1 * 100
      expect(summary.trend).toBe('up');
    });

    it('should report trend=down when current < previous', () => {
      makeOrder(orderRepo, { id: 'o-prev1', userId: 'u1', createdAt: new Date('2023-12-10') });
      makeOrder(orderRepo, { id: 'o-prev2', userId: 'u1', createdAt: new Date('2023-12-20') });
      makeOrder(orderRepo, { id: 'o-cur1', userId: 'u1', createdAt: new Date('2024-01-10') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('total-orders', query);
      expect(summary.currentValue).toBe(1);
      expect(summary.previousValue).toBe(2);
      expect(summary.changePercent).toBe(-50); // (1-2)/2 * 100
      expect(summary.trend).toBe('down');
    });

    it('should report trend=flat when no change', () => {
      makeOrder(orderRepo, { id: 'o-prev', userId: 'u1', createdAt: new Date('2023-12-15') });
      makeOrder(orderRepo, { id: 'o-cur', userId: 'u1', createdAt: new Date('2024-01-15') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('total-orders', query);
      expect(summary.currentValue).toBe(1);
      expect(summary.previousValue).toBe(1);
      expect(summary.changePercent).toBe(0);
      expect(summary.trend).toBe('flat');
    });

    it('should handle changePercent=0 when previousValue=0', () => {
      makeOrder(orderRepo, { id: 'o-cur', userId: 'u1', createdAt: new Date('2024-01-15') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('total-orders', query);
      expect(summary.currentValue).toBe(1);
      expect(summary.previousValue).toBe(0);
      expect(summary.changePercent).toBe(0); // avoid division by zero
      expect(summary.trend).toBe('flat');
    });

    it('should include timeSeries in the summary', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', createdAt: new Date('2024-01-15') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('total-orders', query);
      expect(summary.timeSeries).toBeInstanceOf(Array);
      expect(summary.timeSeries.length).toBeGreaterThan(0);
    });
  });

  // ─── getTimeSeries ───

  describe('getTimeSeries', () => {
    it('should bucket orders by day', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', createdAt: new Date('2024-01-02T10:00:00Z') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', createdAt: new Date('2024-01-02T14:00:00Z') });
      makeOrder(orderRepo, { id: 'o3', userId: 'u1', createdAt: new Date('2024-01-03T10:00:00Z') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-04'),
        granularity: 'day',
      };
      const series = service.getTimeSeries('total-orders', query);
      expect(series.length).toBe(3); // Jan 1, Jan 2, Jan 3

      // Find the Jan 2 bucket — should have 2 orders
      const jan2 = series.find((p) => p.timestamp.getTime() === new Date('2024-01-02').getTime());
      expect(jan2).toBeDefined();
      expect(jan2!.value).toBe(2);

      // Jan 1 bucket — 0 orders
      const jan1 = series.find((p) => p.timestamp.getTime() === new Date('2024-01-01').getTime());
      expect(jan1).toBeDefined();
      expect(jan1!.value).toBe(0);
    });

    it('should bucket orders by hour', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', createdAt: new Date('2024-01-01T10:30:00Z') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', createdAt: new Date('2024-01-01T10:45:00Z') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01T10:00:00Z'),
        endDate: new Date('2024-01-01T12:00:00Z'),
        granularity: 'hour',
      };
      const series = service.getTimeSeries('total-orders', query);
      expect(series.length).toBe(2); // 10:00, 11:00
      expect(series[0]!.value).toBe(2); // both in 10:00 bucket
      expect(series[1]!.value).toBe(0); // 11:00 bucket empty
    });

    it('should bucket by month', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', total: 100, createdAt: new Date('2024-01-15') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', total: 200, createdAt: new Date('2024-02-15') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-03-01'),
        granularity: 'month',
      };
      const series = service.getTimeSeries('total-revenue', query);
      expect(series.length).toBe(2); // Jan, Feb
      expect(series[0]!.value).toBe(100);
      expect(series[1]!.value).toBe(200);
    });

    it('should return empty buckets when no orders in range', () => {
      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-04'),
        granularity: 'day',
      };
      const series = service.getTimeSeries('total-orders', query);
      expect(series.length).toBe(3);
      expect(series.every((p) => p.value === 0)).toBe(true);
    });

    it('should format labels correctly for day granularity', () => {
      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-03'),
        granularity: 'day',
      };
      const series = service.getTimeSeries('total-orders', query);
      // Labels should be like "Jan 1", "Jan 2"
      expect(series[0]!.label).toMatch(/Jan/);
    });

    it('should return no buckets for zero-duration range', () => {
      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-01'),
        granularity: 'day',
      };
      const series = service.getTimeSeries('total-orders', query);
      expect(series.length).toBe(0);
    });
  });

  // ─── getOrderStatusBreakdown ───

  describe('getOrderStatusBreakdown', () => {
    it('should group orders by status with correct counts and percentages', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', status: 'pending', createdAt: new Date('2024-01-10') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', status: 'pending', createdAt: new Date('2024-01-11') });
      makeOrder(orderRepo, { id: 'o3', userId: 'u1', status: 'delivered', createdAt: new Date('2024-01-12') });
      makeOrder(orderRepo, { id: 'o4', userId: 'u1', status: 'cancelled', createdAt: new Date('2024-01-13') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const breakdown = service.getOrderStatusBreakdown(query);

      expect(breakdown.length).toBe(3); // pending, delivered, cancelled

      const pending = breakdown.find((b) => b.status === 'pending');
      expect(pending).toBeDefined();
      expect(pending!.count).toBe(2);
      expect(pending!.percent).toBe(50);

      const delivered = breakdown.find((b) => b.status === 'delivered');
      expect(delivered).toBeDefined();
      expect(delivered!.count).toBe(1);
      expect(delivered!.percent).toBe(25);
    });

    it('should return empty array when no orders in range', () => {
      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const breakdown = service.getOrderStatusBreakdown(query);
      expect(breakdown).toEqual([]);
    });

    it('should handle single status', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', status: 'shipped', createdAt: new Date('2024-01-10') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', status: 'shipped', createdAt: new Date('2024-01-11') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const breakdown = service.getOrderStatusBreakdown(query);
      expect(breakdown.length).toBe(1);
      expect(breakdown[0]!.status).toBe('shipped');
      expect(breakdown[0]!.count).toBe(2);
      expect(breakdown[0]!.percent).toBe(100);
    });
  });

  // ─── getDashboard ───

  describe('getDashboard', () => {
    it('should return full dashboard with all four metric summaries', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', total: 50, status: 'delivered', createdAt: new Date('2024-01-15') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const dashboard = service.getDashboard(query);

      expect(dashboard.summaries.length).toBe(4);
      expect(dashboard.summaries.map((s) => s.metric).sort()).toEqual([
        'active-users',
        'order-completion-rate',
        'total-orders',
        'total-revenue',
      ]);
      expect(dashboard.ordersByStatus.length).toBe(1);
      expect(dashboard.generatedAt).toBeInstanceOf(Date);
      expect(dashboard.query).toEqual(query);

      // Verify values are correct
      const revenue = dashboard.summaries.find((s) => s.metric === 'total-revenue');
      expect(revenue!.currentValue).toBe(50);
    });

    it('should return zeroed dashboard when no data', () => {
      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const dashboard = service.getDashboard(query);

      expect(dashboard.summaries.length).toBe(4);
      for (const s of dashboard.summaries) {
        expect(s.currentValue).toBe(0);
      }
      expect(dashboard.ordersByStatus).toEqual([]);
    });
  });

  // ─── userId filtering ───

  describe('userId filtering', () => {
    it('should filter metrics to a specific user', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', total: 100, createdAt: new Date('2024-01-10') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u2', total: 200, createdAt: new Date('2024-01-11') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
        userId: 'u1',
      };
      const summary = service.getMetricSummary('total-revenue', query);
      expect(summary.currentValue).toBe(100);
    });

    it('should filter order status breakdown by userId', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', status: 'pending', createdAt: new Date('2024-01-10') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u2', status: 'delivered', createdAt: new Date('2024-01-11') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
        userId: 'u1',
      };
      const breakdown = service.getOrderStatusBreakdown(query);
      expect(breakdown.length).toBe(1);
      expect(breakdown[0]!.status).toBe('pending');
    });
  });

  // ─── Edge cases ───

  describe('edge cases', () => {
    it('should handle a single data point', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', total: 42, createdAt: new Date('2024-01-15T12:00:00Z') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-15'),
        endDate: new Date('2024-01-16'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('total-revenue', query);
      expect(summary.currentValue).toBe(42);
      expect(summary.timeSeries.length).toBe(1);
    });

    it('should handle large datasets', () => {
      // Create 100 orders
      for (let i = 0; i < 100; i++) {
        const day = (i % 28) + 1;
        const dayStr = String(day).padStart(2, '0');
        makeOrder(orderRepo, {
          id: `o${i}`,
          userId: `u${i % 10}`,
          total: 10,
          status: (i % 2 === 0 ? 'delivered' : 'pending') as OrderStatus,
          createdAt: new Date(`2024-01-${dayStr}T12:00:00Z`),
        });
      }

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-31'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('total-orders', query);
      expect(summary.currentValue).toBe(100);

      const users = service.getMetricSummary('active-users', query);
      expect(users.currentValue).toBe(10);

      const revenue = service.getMetricSummary('total-revenue', query);
      expect(revenue.currentValue).toBe(1000);

      const completion = service.getMetricSummary('order-completion-rate', query);
      expect(completion.currentValue).toBe(50); // half delivered
    });

    it('should handle orders exactly at boundary dates', () => {
      makeOrder(orderRepo, { id: 'o-start', userId: 'u1', createdAt: new Date('2024-01-01T00:00:00Z') });
      makeOrder(orderRepo, { id: 'o-end', userId: 'u1', createdAt: new Date('2024-01-31T00:00:00Z') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01T00:00:00Z'),
        endDate: new Date('2024-01-31T00:00:00Z'),
        granularity: 'day',
      };
      const summary = service.getMetricSummary('total-orders', query);
      expect(summary.currentValue).toBe(2);
    });

    it('should handle week granularity', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', createdAt: new Date('2024-01-03') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', createdAt: new Date('2024-01-10') });

      const query: AnalyticsQuery = {
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-01-15'),
        granularity: 'week',
      };
      const series = service.getTimeSeries('total-orders', query);
      expect(series.length).toBe(2); // 2 weeks
      expect(series[0]!.value).toBe(1);
      expect(series[1]!.value).toBe(1);
    });
  });
});

